final:
module RefModule (
    input clk,
    input reset_n,
    input serial_in,
    output reg [3:0] reg_out);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset_n or posedge dbg_halt) begin
    if (!reset_n)
        reg_out <= 4'b0000;
    else
        reg_out <= {serial_in, reg_out[3:1]};
end

endmodule
